--
-- Table structure for table `schemes`
--

CREATE TABLE `schemes` (
  `iSchemesId` int(11) NOT NULL,
  `category` varchar(222) NOT NULL,
  `schemes_name` varchar(222) NOT NULL,
  `financier_name` varchar(222) NOT NULL,
  `financier_team_vertical` varchar(222) NOT NULL,
  `minimum_volume` varchar(222) NOT NULL,
  `maximum_volume` varchar(222) NOT NULL,
  `tenure_emi` varchar(222) NOT NULL,
  `commission` varchar(222) NOT NULL,
  `active` int(11) NOT NULL,
  `create_date` datetime NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

